script:
(function () {
  function setGreeting(fullName) {
    const hour = new Date().getHours();
    let timeOfDay = "";
    let emoji = "";

    if (hour >= 5 && hour < 12) {
      timeOfDay = "Good Morning";
      emoji = "☀️";
    } else if (hour >= 12 && hour < 17) {
      timeOfDay = "Good Afternoon";
      emoji = "🌤️";
    } else if (hour >= 17 && hour < 21) {
      timeOfDay = "Good Evening";
      emoji = "🌇";
    } else {
      timeOfDay = "Good Night";
      emoji = "🌙";
    }

    const firstName = (fullName || "there").split(" ")[0];

    const el = root_element.querySelector("#greeting-text");
    if (el) {
      el.innerHTML = `${timeOfDay}, ${firstName} ${emoji}`;
    }
  }

  const bootName =
    frappe?.boot?.full_name ||
    frappe?.boot?.user?.fullname ||
    frappe?.session?.user_fullname ||
    null;

  if (bootName && bootName !== "Guest") {
    setGreeting(bootName);
  } else {
    frappe.call({
      method: "frappe.client.get_value",
      args: {
        doctype: "User",
        filters: { name: frappe.session.user },
        fieldname: "full_name"
      },
      callback: function (r) {
        const name = r?.message?.full_name || "there";
        setGreeting(name);
      }
    });
  }
})();

const user = frappe.session.user;

// ── Status badge helper ──────────────────────────────────────
function statusBadge(status) {
  const map = {
    'Open':      'ts-badge-open',
    'Approved':  'ts-badge-approved',
    'Rejected':  'ts-badge-rejected',
    'Cancelled': 'ts-badge-cancelled'
  };
  const cls = map[status] || 'ts-badge-open';
  return `<span class="ts-badge ${cls}">${status || '—'}</span>`;
}

// ── 1. Summary counts ────────────────────────────────────────
frappe.db.count('Timesheet Submission', { filters: [] }).then(total => {
  root_element.querySelector('#ts-total').textContent = total;
});
['Open','Approved','Rejected'].forEach(s => {
  frappe.db.count('Timesheet Submission', { filters: { status: s } }).then(c => {
    const idMap = { Open:'ts-open', Approved:'ts-approved', Rejected:'ts-rejected' };
    root_element.querySelector('#' + idMap[s]).textContent = c;
  });
});

// ── 2. Recent submissions (last 10) ─────────────────────────
frappe.db.get_list('Timesheet Submission', {
  fields: ['name', 'employee_name', 'month_year', 'total_working_hours', 'status'],
  order_by: 'modified desc',
  limit: 10
}).then(rows => {
  const tbody = root_element.querySelector('#ts-table-body');
  if (!rows || !rows.length) {
    tbody.innerHTML = '<tr><td colspan="6" class="ts-loading">No submissions found.</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map(r => `
    <tr>
      <td><a class="ts-link" data-name="${r.name}">${r.name}</a></td>
      <td>${r.employee_name || '—'}</td>
      <td>${r.month_year || '—'}</td>
      <td>${r.total_working_hours ? parseFloat(r.total_working_hours).toFixed(1) + ' hrs' : '—'}</td>
      <td>${statusBadge(r.status)}</td>
      <td><a class="ts-link" data-name="${r.name}">Open</a></td>
    </tr>
  `).join('');

  // Row click → open doc
  root_element.querySelectorAll('.ts-link').forEach(el => {
    el.addEventListener('click', () => {
      frappe.set_route('Form', 'Timesheet Submission', el.dataset.name);
    });
  });
});

// ── 3. Timesheet Per Project (child table) ───────────────────
frappe.call({
  method: 'frappe.client.get_list',
  args: {
    doctype: 'Timesheet Submission',
    fields: [
      'name',
      '`tabTimesheet Submission List`.project',
      '`tabTimesheet Submission List`.project_name',
      '`tabTimesheet Submission List`.total_hours',
      '`tabTimesheet Submission List`.status',
      '`tabTimesheet Submission List`.month',
      '`tabTimesheet Submission List`.pay',
    ],
    filters: [],
    limit: 100
  },
  callback(r) {
    const container = root_element.querySelector('#ts-project-cards');
    root_element.querySelector('#ts-project-loading')?.remove();

    const rows = r.message;
    if (!rows || !rows.length) {
      container.innerHTML = '<div class="col-12 ts-loading">No project timesheet data found.</div>';
      return;
    }

    // Group by project
    const grouped = {};
    rows.forEach(r => {
      const key = r.project || 'Unassigned';
      if (!grouped[key]) grouped[key] = { project_name: r.project_name || key, rows: [], totalHrs: 0 };
      grouped[key].rows.push(r);
      grouped[key].totalHrs += parseFloat(r.total_hours || 0);
    });

    const cards = Object.entries(grouped).map(([proj, data]) => {
      const statusCounts = {};
      data.rows.forEach(r => {
        statusCounts[r.status] = (statusCounts[r.status] || 0) + 1;
      });
      const statusPills = Object.entries(statusCounts)
        .map(([s, c]) => `${statusBadge(s)} <span class="ts-pill-count">${c}</span>`)
        .join(' ');

      const latestMonth = data.rows[0]?.month || '—';
      const totalPay = data.rows.reduce((sum, r) => sum + parseFloat(r.pay || 0), 0);

      return `
        <div class="col-12 col-sm-6 col-lg-4 mb-3">
          <div class="ts-proj-card">
            <div class="ts-proj-name">${data.project_name}</div>
            <div class="ts-proj-id">${proj}</div>
            <hr class="ts-hr-sm">
            <div class="d-flex justify-content-between mb-1">
              <span class="ts-meta-label">Total Hours</span>
              <span class="ts-meta-val">${data.totalHrs.toFixed(1)} hrs</span>
            </div>
            <div class="d-flex justify-content-between mb-1">
              <span class="ts-meta-label">Entries</span>
              <span class="ts-meta-val">${data.rows.length}</span>
            </div>
            <div class="d-flex justify-content-between mb-1">
              <span class="ts-meta-label">Latest Month</span>
              <span class="ts-meta-val">${latestMonth}</span>
            </div>
            ${totalPay > 0 ? `
            <div class="d-flex justify-content-between mb-1">
              <span class="ts-meta-label">Total Pay</span>
              <span class="ts-meta-val">KES ${frappe.utils.fmt_money(totalPay)}</span>
            </div>` : ''}
            <div class="mt-2">${statusPills}</div>
          </div>
        </div>
      `;
    }).join('');

    container.innerHTML = cards;
  }
});

// ── 4. Submission reports button ─────────────────────────────────
root_element.querySelector('#ts-rp-btn').addEventListener('click', () => {
  frappe.set_route('app/timesheet_workflow');
});

style:
.ts-block {
  font-family: inherit;
  color: var(--text-color);
  padding: 4px 2px;
}

/* Header */
.ts-title {
  font-size: 15px;
  font-weight: 600;
  color: var(--heading-color, var(--text-color));
  margin-bottom: 2px;
}
.ts-sub {
  font-size: 12px;
  color: var(--text-muted);
}
.ts-btn-rp {
  font-size: 12px;
  font-weight: 500;
  padding: 6px 14px;
  border-radius: var(--border-radius, 6px);
  border: 1px solid var(--primary);
  color: var(--primary);
  background: transparent;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}
.ts-btn-rp:hover {
  background: var(--primary);
  color: #fff;
}

/* Dividers */
.ts-hr {
  border: none;
  border-top: 1px solid var(--border-color);
  margin: 14px 0;
  opacity: 1;
}
.ts-hr-sm {
  border: none;
  border-top: 1px solid var(--border-color);
  margin: 10px 0 10px;
  opacity: 1;
}

/* Section title */
.ts-section-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--heading-color, var(--text-color));
}

/* Summary stat cards */
.ts-stat-card {
  border: 1px solid var(--border-color);
  border-radius: var(--border-radius, 6px);
  padding: 16px 14px;
  text-align: center;
  height: 100%;
}
.ts-stat-val {
  font-size: 28px;
  font-weight: 700;
  color: var(--primary);
  line-height: 1;
  margin-bottom: 4px;
}
.ts-stat-val.ts-open     { color: var(--blue, #1e73be); }
.ts-stat-val.ts-approved { color: var(--green, #28a745); }
.ts-stat-val.ts-rejected { color: var(--red, #e53935); }
.ts-stat-label {
  font-size: 11px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

/* Project cards */
.ts-proj-card {
  border: 1px solid var(--border-color);
  border-radius: var(--border-radius, 6px);
  padding: 16px;
  height: 100%;
  transition: border-color 0.15s, background 0.15s;
}
.ts-proj-card:hover {
  border-color: var(--primary);
  background: rgba(30, 115, 190, 0.03);
}
.ts-proj-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-color);
  margin-bottom: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.ts-proj-id {
  font-size: 11px;
  color: var(--text-muted);
  margin-bottom: 2px;
}
.ts-meta-label {
  font-size: 12px;
  color: var(--text-muted);
}
.ts-meta-val {
  font-size: 12px;
  font-weight: 500;
  color: var(--text-color);
}
.ts-pill-count {
  font-size: 11px;
  color: var(--text-muted);
}

/* Status badges */
.ts-badge {
  display: inline-block;
  font-size: 10px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 20px;
  letter-spacing: 0.03em;
  text-transform: uppercase;
}
.ts-badge-open      { background: rgba(30,115,190,0.1);  color: var(--blue,  #1e73be); }
.ts-badge-approved  { background: rgba(40,167,69,0.1);   color: var(--green, #28a745); }
.ts-badge-rejected  { background: rgba(229,57,53,0.1);   color: var(--red,   #e53935); }
.ts-badge-cancelled { background: rgba(108,117,125,0.1); color: var(--gray,  #6c757d); }

/* Table */
.ts-table-wrap {
  overflow-x: auto;
}
.ts-table {
  border-collapse: collapse;
  font-size: 12px;
  min-width: 560px;
}
.ts-table thead tr {
  border-bottom: 2px solid var(--border-color);
}
.ts-table th {
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 8px 10px;
  white-space: nowrap;
  text-align: left;
}
.ts-table td {
  padding: 9px 10px;
  border-bottom: 1px solid var(--border-color);
  color: var(--text-color);
  vertical-align: middle;
}
.ts-table tbody tr:hover td {
  background: rgba(30,115,190,0.03);
}
.ts-link {
  color: var(--primary);
  cursor: pointer;
  text-decoration: none;
  font-weight: 500;
}
.ts-link:hover {
  text-decoration: underline;
}
.ts-loading {
  font-size: 12px;
  color: var(--text-muted);
  padding: 12px 0;
}

